import axios, { AxiosInstance, AxiosRequestConfig, AxiosResponse } from 'axios';
import JSONBigInt from 'json-bigint';
import { SpotterResponseResultSchema } from './type';

const JSONBig2String = JSONBigInt({ storeAsString: true, constructorAction: 'preserve', protoAction: 'preserve' });
const defaultStatusSetMap = {
    authError: new Set([401, 403]),
    success: new Set([200, 201]),
};

type OmittedAxiosOptions =
    | 'url'
    | 'method'
    | 'baseURL'
    | 'data'
    | 'params'
    | 'paramsSerializer'
    | 'transformResponse'
    | 'transformRequest'
    | 'withCredentials';

export interface HttpClientOptions<D = any> {
    context: URL;
    res: {
        isSuccess?: (response: AxiosResponse) => boolean;
        isAuthError?: (response: AxiosResponse) => boolean;
        onAuthError: (error: any) => void;
        onOtherError: (error: any) => void;
    };
    axiosOptions?: Omit<AxiosRequestConfig<D>, OmittedAxiosOptions>;
}

export default class HttpClient {
    private readonly httpClient: AxiosInstance;
    private options: Required<HttpClientOptions>;
    constructor(options: HttpClientOptions) {
        this.options = options as Required<HttpClientOptions>;
        this.options.res.isSuccess =
            options.res?.isSuccess ??
            ((res) =>
                defaultStatusSetMap.success.has(res.status));
        this.options.res.isAuthError =
            options.res?.isAuthError ??
            ((res) =>
                defaultStatusSetMap.authError.has(res.status));

        this.httpClient = axios.create({
            ...this.options.axiosOptions,
            baseURL: this.options.context.href,
            withCredentials: true, // CORS with cookies,
            transformResponse: [(data) => JSONBig2String.parse(data)],
        });
        this.httpClient.interceptors.request.use(
            (config) => {
                if (!config.data) {
                    config.data = {};
                }
                return config;
            },
            (error) => {
                console.log('request', error);
                return Promise.reject(error);
            },
        );

        // 响应拦截器
        this.httpClient.interceptors.response.use(
            (response) => {
                if (this.options.res.isSuccess!(response)) {
                    return Promise.resolve(response);
                }
                if (this.options.res.isAuthError!(response)) {
                    console.log(response);
                    this.options.res.onAuthError(response);
                } else {
                    this.options.res.onOtherError(response);
                    // content: error.response.data?.message || 'Network Error'
                    console.error(JSON.stringify(response.data));
                }
                return Promise.reject(response);
            },
            (error) => {
                if (this.options.res.isAuthError!(error)) {
                    console.log(error);
                    this.options.res.onAuthError(error);
                } else {
                    this.options.res.onOtherError(error);
                    // content: error.response.data?.message || 'Network Error'
                    console.error(JSON.stringify(error.response));
                }
                return Promise.reject(error);
            },
        );
    }

    async request<T = any, S = SpotterResponseResultSchema<T> >(config: AxiosRequestConfig) {
        return this.httpClient.request<S>(config);
    }
    getAxios() {
        return this.httpClient;
    }
}